params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_診療科聴取 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"呼吸器系統": "1", "脳神経系統": "1", "循環器系統": "1", "腫瘍系統": "1", "精神系統": "1", "放射線系統": "1", "小児系統": "1", "スポーツ系統": "1", "放射線治療科": "1", "内科": "1", "外科": "2", "救急科": "2", "健康センター": "2", "放射線科": "2", "内視鏡": "2", "PETCT": "2", "心療内科": "2", "美容整形": "2", "精神神経科": "2", "皮膚科": "2", "麻酔科": "3", "わからない": "3", "other": "3"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 3 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_診療科聴取");
var mapping = {"呼吸器系統": "1", "脳神経系統": "1", "循環器系統": "1", "腫瘍系統": "1", "精神系統": "1", "放射線系統": "1", "小児系統": "1", "スポーツ系統": "1", "放射線治療科": "1", "内科": "1", "外科": "2", "救急科": "2", "健康センター": "2", "放射線科": "2", "内視鏡": "2", "PETCT": "2", "心療内科": "2", "美容整形": "2", "精神神経科": "2", "皮膚科": "2", "麻酔科": "3", "わからない": "3", "other": "3"};
var group = mapping[input];
if (!group) { group = "3"; }
$runner.setResult(group);

// Script Template: business_hours
// 現在時刻が営業時間内か判定
// プレースホルダー: 9, 16 = 営業開始/終了時刻（24時間制、0-23）
// 出力: 営業時間内 / 営業時間外

var now = new Date();
var hour = now.getHours();
var startHour = 9;
var endHour = 16;
var res = "営業時間外";

if (hour >= startHour && hour < endHour) {
    res = "営業時間内";
}

$runner.setResult(res);
